#define LoadInit()\
   int Load3i, Load3j; \
   char Load3Sprite[100]; \
   char Load3Temp[10]; 

#define LoadIsoSquare(Var, Name, x, y)\
   for (Load3j = 0; Load3j < y; Load3j++) {\
      for (Load3i = 0; Load3i < x; Load3i++) {\
         strcpy_s(Load3Sprite,100, Name);\
         strcat_s(Load3Sprite,100, " (");\
	     _itoa_s(Load3i+1, Load3Temp,10, 10);\
         strcat_s(Load3Sprite,100, Load3Temp);\
         strcat_s(Load3Sprite,100, ", ");\
		 _itoa_s(Load3j+1, Load3Temp,10, 10);\
         strcat_s(Load3Sprite,100, Load3Temp);\
         strcat_s(Load3Sprite,100, ")");\
         Var[Load3j][Load3i].LoadSprite(Load3Sprite);\
      }\
   }

