template <class type>
DWORD RLE_Decompress(type *lpCompress, type *lpDecompress, DWORD dwLen, DWORD dwMax, DWORD dwLimit) 
{
	DWORD nCountD = 0;
   long nCountC = 0;
   type dwData = 0;
   long nBytes;
   
   while (nCountD < dwLen) 
   {
      dwData = lpCompress[nCountC];
      nCountC++;
      if (dwData > dwLimit) 
      {
         nBytes = dwData - dwLimit;
         dwData = lpCompress[nCountC];
         nCountC++;
         for (int i = nBytes; i > 0; i--) 
         {
            if(nCountD < dwLen )
               lpDecompress[nCountD] = dwData;
            nCountD++;
         }
      } 
      else 
      {
         if(nCountD < dwLen )
            lpDecompress[nCountD] = dwData;
         nCountD++;
      }
   }

   return nCountD;
}

template <class type>
DWORD RLE_DecompressA(type *lpCompress, type *lpDecompress, DWORD dwLen, DWORD dwMax, DWORD dwLimit) 
{
   DWORD nCountD = 0;
   long nCountC = 0;
   type dwData = 0;
   long nBytes;

   while (nCountD < dwLen) 
   {
      dwData = lpCompress[nCountC];
      nCountC++;
      if (dwData > dwLimit) 
      {
         nBytes = dwData - dwLimit;
         dwData = lpCompress[nCountC];
         nCountC++;
         for (int i = nBytes; i > 0; i--) 
         {
            if(nCountD < dwLen )
               lpDecompress[nCountD] = dwData;
            nCountD++;
         }
      } 
      else 
      {
         if(nCountD < dwLen )
            lpDecompress[nCountD] = dwData;
         nCountD++;
      }
   }

   return nCountD;
}

template <class type>
DWORD RLE_Compress(type *lpCompress, type*lpDecompress, DWORD dwLen, DWORD dwMax, DWORD dwLimit) {
   long nCountD = 0;
   long nCountC = 0;
   type dwData = 0;
   long nBytes = 0;

   while (nCountD < dwLen) {
      dwData = lpDecompress[nCountD];
      nCountD++;
      if (dwData == lpDecompress[nCountD] && (nBytes < dwMax-dwLimit) && nCountD < dwLen) {
         nBytes++;
      } else {
         if (nBytes || dwData >= dwLimit) {
            nBytes++;
            lpCompress[nCountC] = nBytes+dwLimit;
            nCountC++;
            lpCompress[nCountC] = dwData;
            nCountC++;
            nBytes = 0;
         } else {
            lpCompress[nCountC] = dwData;
            nCountC++;
         }
      }
   }

   return nCountC;
}

TileSetException::TileSetException(TileSetError Error) {
// Error in TileSet Class
	switch (Error) {
		case NOT_DEFINED_VIEW:
//			TRACE("TileSetException: View and/or Virtual View Width and/or isn't defined. No View Created.\r\n");
			throw;
		break;

		case FILE_NOT_FOUND:
//			TRACE("TileSetException: Virtual Map Files Not Found.\r\n");
			throw;
		break;                                                                                  
	} 
}

