int TileSet::GetPosView1(int iX,int iY)
{
   int iNX = iX+m_iLastXLoadDX-m_iLastXLoad;
   int iNY = iY+m_iLastYLoadDY-m_iLastYLoad;
   iNX = NM_Max<int>(0, iNX);
   iNX = NM_Min<int>(iNX, VirtualWidth-1);
   iNY = NM_Max<int>(0, iNY);
   iNY = NM_Min<int>(iNY, VirtualHeight-1);
   return VirtualView1[(iNY*VirtualWidth)+iNX];
}

int TileSet::GetPosViewM(int iX,int iY)
{
   int iNX = iX+m_iLastXLoadDX-m_iLastXLoad;
   int iNY = iY+m_iLastYLoadDY-m_iLastYLoad;
   iNX = NM_Max<int>(0, iNX);
   iNX = NM_Min<int>(iNX, VirtualWidth-1);
   iNY = NM_Max<int>(0, iNY);
   iNY = NM_Min<int>(iNY, VirtualHeight-1);
   return VirtualViewM[(iNY*VirtualWidth)+iNX];
}

int TileSet::GetPosViewL(int iX,int iY)
{
   int iNX = iX+m_iLastXLoadDX-m_iLastXLoad;
   int iNY = iY+m_iLastYLoadDY-m_iLastYLoad;
   iNX = NM_Max<int>(0, iNX);
   iNX = NM_Min<int>(iNX, VirtualWidth-1);
   iNY = NM_Max<int>(0, iNY);
   iNY = NM_Min<int>(iNY, VirtualHeight-1);
   return VirtualViewL[(iNY*VirtualWidth)+iNX];
}

int TileSet::GetPosViewX(int iX,int iY)
{
   int iNX = iX+m_iLastXLoadDX-m_iLastXLoad;
   int iNY = iY+m_iLastYLoadDY-m_iLastYLoad;
   iNX = NM_Max<int>(0, iNX);
   iNX = NM_Min<int>(iNX, VirtualWidth-1);
   iNY = NM_Max<int>(0, iNY);
   iNY = NM_Min<int>(iNY, VirtualHeight-1);
   return VirtualViewX[(iNY*VirtualWidth)+iNX];
}



