void TileSet::SetPosition(int NewX, int NewY, int NewWorld, BOOL F,BOOL ForceName) {
   
// Set the new x,y position.
	int i, j;
	int xScreen, yScreen;
	RECT Clip;

   SepX = SepX2  = 0;
   SepY = SepY2  = 0;
   Middle = 0;
   MovX = MovY = Done = 0;

	xPos = (VirtualWidth  >> 1);
	yPos = (VirtualHeight >> 1);
	wPos = NewWorld;

   Objects.ClearAnimID(-1);

   if(ForceName)
   {
      // on commence par loader la map du new world...
      g_Global.LoadZoneMapWorld(wPos,NewX,NewY);
      g_Global.ForceDisplayZone(NewX,NewY);
   }

	LoadVirtualMap(NewX - xPos, NewY - yPos, NewWorld); 

	// Initialise 
	for (i = 0; i < ViewWidth+Square+Square; i++) 
   {
		for (j = 0; j < ViewHeight+Square+Square; j++) 
      {
         int iPos = i+j*(ViewWidth+Square+Square);
         if((i-1-(ViewWidth>>1)-Square+xPos+(j-2-(ViewHeight>>1)-Square+yPos)*VirtualWidth)< 0xFFFF)
         {
            
			   CompiledView1[iPos] = VirtualView1[i-1-(ViewWidth>>1)-Square+xPos+(j-2-(ViewHeight>>1)-Square+yPos)*VirtualWidth];
            CompiledView2[iPos] = VirtualView2[i-1-(ViewWidth>>1)-Square+xPos+(j-2-(ViewHeight>>1)-Square+yPos)*VirtualWidth];
            CompiledViewA[iPos] = VirtualViewA[i-1-(ViewWidth>>1)-Square+xPos+(j-2-(ViewHeight>>1)-Square+yPos)*VirtualWidth];
         }
         else
         {
            CompiledView1[iPos] = 20;
            CompiledView2[iPos] = 0;
            CompiledViewA[iPos] = 0;
         }
		}
	}

	Clip.left = 0;
	Clip.top = 0;
	Clip.right = g_Global.GetScreenW()+96; //TimeWith*3
	Clip.bottom = g_Global.GetScreenH()+48;//TileHeight*3
	

   //NMNMNMNMNMNM://Draw the FLOOR LEVEL...
	yScreen = -(Square*TileHeight);//+(TileHeight>>1); // Init starting y sprite position.
	for (j = 0; j < ViewHeight+Square+Square; j++) 
   {
	   // Loop thru all the y component.
		xScreen = (ViewWidth+Square-1)*TileWidth;//+(TileWidth>>1); // Init starting x sprite position
		for (i = ViewWidth+Square+Square-1; i > -1; i--) 
      {
		   // Loop thru all the x component.
			a = i;
			b = j;
         if(CompiledViewA[i+(j-Middle)*(ViewWidth+Square+Square)] ==0)
				DrawTileSet(xScreen, yScreen, CompiledView1[i+j*(ViewWidth+Square+Square)], &Clip, NULL, NULL, false, lpFractalSurface, false, FALSE);
         else
         {
            if(!DrawTileSetA(xScreen, yScreen, CompiledViewA[i+j*(ViewWidth+Square+Square)], &Clip, NULL, NULL, false, lpFractalSurface, false, FALSE,i,j,(ViewWidth+Square+Square)))
               DrawTileSet(xScreen, yScreen, CompiledView1[i+j*(ViewWidth+Square+Square)], &Clip, NULL, NULL, false, lpFractalSurface, false, FALSE);
         }

         xScreen -= TileWidth;
		}
		yScreen += TileHeight;
	}

   if(!Custom.gHIDEAllDecors)
   {
      //NMNMNMNMNMNM://Draw the Decors Level Without overlap
      yScreen = -(Square*TileHeight);//+(TileHeight>>1); // Init starting y sprite position.
      for (j = 0; j < ViewHeight+Square+Square; j++) 
      {
         // Loop thru all the y component.
         xScreen = (ViewWidth+Square-1)*TileWidth;//+(TileWidth>>1); // Init starting x sprite position
         for (i = ViewWidth+Square+Square-1; i > -1; i--) 
         {
            // Loop thru all the x component.
            a = i;
            b = j;

            if (CompiledView2[i+(j-Middle)*(ViewWidth+Square+Square)] < SPECIAL_S || (CompiledView2[i+(j-Middle)*(ViewWidth+Square+Square)] >SPECIAL_E && CompiledView2[i+(j-Middle)*(ViewWidth+Square+Square)] <SPECIAL_S2)) 
            {
               if(CompiledView2[i+(j-Middle)*(ViewWidth+Square+Square)] >0)
                  DrawTileSet(xScreen, yScreen, CompiledView2[i+j*(ViewWidth+Square+Square)], &Clip, NULL, NULL, false, lpFractalSurface, false, FALSE);
            }
         
            xScreen -= TileWidth;
         }
         yScreen += TileHeight;
	   }

      //NMNMNMNMNMNM://Draw the Decors Level WITH overlap

	   yScreen = -(Square*TileHeight);//+(TileHeight>>1); // Init starting y sprite position.
	   for (j = 0; j < ViewHeight+Square+Square; j++) 
      {
	      // Loop thru all the y component.
		   xScreen = (ViewWidth+Square-1)*TileWidth;//+(TileWidth>>1); // Init starting x sprite position
		   for (i = ViewWidth+Square+Square-1; i > -1; i--) 
         {
		      // Loop thru all the x component.
			   a = i;
			   b = j;
			   if ((CompiledView2[i+(j-Middle)*(ViewWidth+Square+Square)] > SPECIAL_S  && CompiledView2[i+(j-Middle)*(ViewWidth+Square+Square)] <= SPECIAL_E ) || 
                (CompiledView2[i+(j-Middle)*(ViewWidth+Square+Square)] > SPECIAL_S2 && CompiledView2[i+(j-Middle)*(ViewWidth+Square+Square)] <= SPECIAL_E2)    ) 
            {
               if(CompiledView2[i+(j-Middle)*(ViewWidth+Square+Square)] >0)
				      DrawTileSet(xScreen, yScreen, CompiledView2[i+j*(ViewWidth+Square+Square)], &Clip, NULL, NULL, false, lpFractalSurface, false, FALSE);
			   }

			   xScreen -= TileWidth;
		   }
		   yScreen += TileHeight;
	   }
   }

	ScreenDest.left         = 0;
	ScreenDest.top          = 0;
	ScreenDest.right        = (ViewWidth-1) *TileWidth;
	ScreenDest.bottom       = (ViewHeight-1)*TileHeight;
	
	SmoothSource.left       = TileWidth+TileWidth/2;
	SmoothSource.top        = TileHeight+TileHeight/2;
	SmoothSource.right      = TileWidth *ViewWidth +TileWidth-TileWidth/2;
	SmoothSource.bottom     = TileHeight*ViewHeight+TileHeight-TileHeight/2;

	SurfaceDest.left        = 0;
	SurfaceDest.top         = 0;
	SurfaceDest.right       = TileWidth *ViewWidth +TileWidth *2;
	SurfaceDest.bottom      = TileHeight*ViewHeight+TileHeight*2;

	SurfaceSource.left      = 0;
	SurfaceSource.top       = 0;
	SurfaceSource.right     = TileWidth *ViewWidth +TileWidth *2;
	SurfaceSource.bottom    = TileHeight*ViewHeight+TileHeight*2;

	FractalSource[0].left   = TileWidth;
	FractalSource[0].top    = TileHeight;
	FractalSource[0].right  = TileWidth *ViewWidth +TileWidth*2;
	FractalSource[0].bottom = TileHeight*ViewHeight+TileHeight*2;

   SepX = SepX2 = 0;
   SepY = SepY2 = 0;

   DestRect[0].left     = 0;
   DestRect[0].top      = 0;
   DestRect[0].right    = ViewWidth *TileWidth +TileWidth *2-SepX;
   DestRect[0].bottom   = ViewHeight*TileHeight+TileHeight*2-SepY;
   
   DestRect[1].left     = 0;
   DestRect[1].top      = ViewHeight*TileHeight+TileHeight*2-SepY;
   DestRect[1].right    = ViewWidth *TileWidth +TileWidth *2-SepX;
   DestRect[1].bottom   = ViewHeight*TileHeight+TileHeight*2;
   
   DestRect[2].left     = ViewWidth *TileWidth +TileWidth *2-SepX;
   DestRect[2].top      = 0;
   DestRect[2].right    = ViewWidth *TileWidth +TileWidth *2;
   DestRect[2].bottom   = ViewHeight*TileHeight+TileHeight*2-SepY;
   
   DestRect[3].left     = ViewWidth *TileWidth +TileWidth *2-SepX;
   DestRect[3].top      = ViewHeight*TileHeight+TileHeight*2-SepY;
   DestRect[3].right    = ViewWidth *TileWidth +TileWidth *2;
   DestRect[3].bottom   = ViewHeight*TileHeight+TileHeight*2;
   
   SourceRect[0].left   = SepX;
   SourceRect[0].top    = SepY;
   SourceRect[0].right  = TileWidth *ViewWidth +TileWidth *2;
   SourceRect[0].bottom = TileHeight*ViewHeight+TileHeight*2;
   
   SourceRect[1].left   = SepX;
   SourceRect[1].top    = 0;
   SourceRect[1].right  = TileWidth*ViewWidth+TileWidth*2;
   SourceRect[1].bottom = SepY;
   
   SourceRect[2].left   = 0;
   SourceRect[2].top    = SepY;
   SourceRect[2].right  = SepX;
   SourceRect[2].bottom = TileHeight*ViewHeight+TileHeight*2;
   
   SourceRect[3].left   = 0; 
   SourceRect[3].top    = 0;
   SourceRect[3].right  = SepX;
   SourceRect[3].bottom = SepY;
   lpSmoothSurface2->Blt(&SurfaceDest, lpFractalSurface, &SurfaceSource, DDBLT_WAIT, NULL);

	
   if (F) 
   {
      FadeLevel = 0;
		SetFading = true;
   }

   
}

void TileSet::CreateSmooth(void)
{
   std::map<SmoothTile::TileDefinition, SmoothTile> MapTiles;

   char strDFile[1024];
   char strDFileC[1024];
   sprintf_s(strDFile,1024,"Game Files\\SmoothTiles.bin");
   sprintf_s(strDFileC,1024,"%s\\Game Files\\SmoothTiles.bin",Player.ServerName);

   FILE *pfD = NULL;
   fopen_s(&pfD,strDFileC,"rb");
   if(pfD == NULL)
   {
      SmoothTileLoader::LoadFromFile(strDFile, MapTiles);
   }
   else
   {
      fclose(pfD);
      SmoothTileLoader::LoadFromFile(strDFileC, MapTiles);
   }
   SmoothTileLoader::MapToVector(MapTiles, g_VecTiles);
}

