void TileSet::ReleaseSurface()
{

   if(lpPreLightSurface)
      if( lpPreLightSurface->IsLost() == DD_OK )
         lpPreLightSurface->Release();
   lpPreLightSurface = 0;

   if(lpPreLightSurfaceEffect2)
      if( lpPreLightSurfaceEffect2->IsLost() == DD_OK )
       lpPreLightSurfaceEffect2->Release();
   lpPreLightSurfaceEffect2 = 0;

   if(lpSmoothSurface2)
      if( lpSmoothSurface2->IsLost() == DD_OK )
       lpSmoothSurface2->Release();
   lpSmoothSurface2 = 0;

   if(lpSmoothTemp)
      if( lpSmoothTemp->IsLost() == DD_OK )
         lpSmoothTemp->Release();
   lpSmoothTemp = 0;

   if(lpFractalSurface)
      if( lpFractalSurface->IsLost() == DD_OK )
         lpFractalSurface->Release();
   lpFractalSurface = 0;
}


